  ('diplomatic-823d6974-moex-00353', 'diplomatic-823d6974', 'diplomatic-823d6974-moex-112-7f4830a9', 'sub-diplomatic-823d6974-04', NULL, 'single_choice', '有關清朝末年邊疆爭端的敘述，下列何者正確？', '["咸豐6年（1856年），回變最早起於雲南，其得到沙俄的外交支持，並以馬如龍、杜文秀勢力 最大", "咸豐8年（1858年），第一次英法聯軍進逼天津，沙俄將領莫拉維也夫（NikolayN.Muravyov） 乘機出兵璦琿，威逼李鴻章，簽訂《璦琿條約》", "同治3年（1864年）新疆回變，中亞浩罕國國王派部將阿古柏（MuhammadYaqubBek）東來， 建立回教汗國，最後由曾國藩西征討平", "新疆回變發生，沙俄軍隊於同治10年（1871年）佔據伊犂。清廷派遣駐英法大臣曾紀澤前往 聖彼得堡談判，始得爭回部分領土權益"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:36+00:00", "source_pdf_sha1": "cb69610e8100", "answer_pdf_sha1": "f2cb8661297c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-阿拉伯文組"}'::jsonb, NULL),
  ('diplomatic-823d6974-moex-00354', 'diplomatic-823d6974', 'diplomatic-823d6974-moex-112-7f4830a9', 'sub-diplomatic-823d6974-04', NULL, 'single_choice', '1899年美國國務卿海約翰（JohnHay）主張中國門戶開放政策，下列敘述何者錯誤？', '["美國在美西戰爭獲勝取得菲律賓後實力增強", "美國在中國商業利益逐漸增多", "美國主張各國門戶開放原是外交傳統", "美國以尊重列強在中國勢力範圍取得的特權爭取支持"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:36+00:00", "source_pdf_sha1": "cb69610e8100", "answer_pdf_sha1": "f2cb8661297c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-阿拉伯文組"}'::jsonb, NULL),
  ('diplomatic-823d6974-moex-00355', 'diplomatic-823d6974', 'diplomatic-823d6974-moex-112-7f4830a9', 'sub-diplomatic-823d6974-04', NULL, 'single_choice', '有關於第二次世界大戰期間，同盟國之間的合作，下列敘述何者正確？', '["民國26年（1937年）「七七事變」爆發，美、英為加強對華友誼，迅即撤銷不平等條約", "民國32年（1943年）11月，美國總統羅斯福（FranklinD.Roosevelt）、英國首相邱吉爾（Winston Churchill），邀請國民政府主席蔣中正前往開羅，並發表《開羅宣言》，同意戰後朝鮮獨立", "民國 33 年（1944 年）10 月，中華民國與美、英、法共同宣布《聯合國組織案》，成為「聯合 國」的創始會員國", "民國34年（1945年），希特勒（AdolfHitler）敗亡前，中、美、英3國發表《波茨坦宣言》，要 求德國無條件投降"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:36+00:00", "source_pdf_sha1": "cb69610e8100", "answer_pdf_sha1": "f2cb8661297c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-阿拉伯文組"}'::jsonb, NULL)
